from pathlib import Path
path=Path(r'D:\Projects\bazi-portal\names.html')
text=path.read_text(encoding='utf-8')
start=text.find('const patterns=')
end=text.rfind('</script></body></html>')
if start==-1 or end==-1 or end<=start:
    raise SystemExit('tail boundary not found')
new_tail = '''const patterns=["火格","土格","木火格","水火格","火土格","金火格"]; const container=document.getElementById('patterns'); const maleBtn=document.getElementById('maleBtn'); const femaleBtn=document.getElementById('femaleBtn'); const body=document.body; const topbar=document.getElementById('namesTopbar'); const MOBILE_BATCH=12; const renderState={男:{},女:{}}; const genderScrollMemory={男:null,女:null}; let suppressScrollMemoryWrite=false; let activePattern=''; function isMobile(){ return window.innerWidth<=720; } function getBatch(pattern){ const key=currentGender; const total=(currentGender==='男'?topData[pattern].boys:topData[pattern].girls).length; if(!isMobile()) return total; const now=renderState[key][pattern]||MOBILE_BATCH; return Math.min(now,total); } function ensureMore(pattern){ const key=currentGender; const total=(currentGender==='男'?topData[pattern].boys:topData[pattern].girls).length; const now=renderState[key][pattern]||MOBILE_BATCH; if(now<total) renderState[key][pattern]=Math.min(now+MOBILE_BATCH,total); } function entryHtml(r,p){ const mobile=isMobile(); return `<div class="name-line"><div class="subline"><div><div class="name-calligraphy" style="${patternStyle[p]}">${r.name}</div><span class="small">${r.pinyin}</span></div><div style="display:flex;flex-direction:column;align-items:flex-end;gap:8px"><div class="score">${r.score} 分</div>${mobile?'<button class="btn detail-toggle" type="button" data-detail-toggle="1">展开详情</button>':''}</div></div><div class="note" ${mobile?'data-detail-body="1" style="display:none"':''}><b>五行：</b>${r.wuxing}<br><b class="meaning">组合意思：</b><span class="meaning">${r.meaning}</span><br><b>出处：</b>${r.source}<br><span class="reason"><b>评分理由：</b><strong>评分 ${r.score}</strong>：${r.reason.replace(/^评分\s*\d+[.:分]?/,'')}</span></div></div>`; } function cardHtml(p){ const list=(currentGender==='男'?topData[p].boys:topData[p].girls); const visible=list.slice(0,getBatch(p)); return `<article class="card pattern-card ${activePattern===p?'active-target':''}" id="${encodeURIComponent(p)}" data-pattern="${p}" style="background-image:${patternBg[p]}"><div class="pattern-headline"><div class="pattern-meta-left"><span class="badge">${patternDirection[p]}</span></div><div class="pattern-title-big" style="${patternStyle[p]}">${p}</div><div class="pattern-meta-right"><span class="badge">${list.length} 个名字</span></div></div>${visible.map(r=>entryHtml(r,p)).join('')}${visible.length<list.length?`<div class="bottom-actions"><button class="btn" data-more="${p}">再看 ${Math.min(MOBILE_BATCH,list.length-visible.length)} 个</button></div>`:''}</article>`; }  function bindAutoLoad(){ if(!isMobile()) return; const io=new IntersectionObserver(entries=>{ entries.forEach(entry=>{ if(!entry.isIntersecting) return; const card=entry.target.closest('.pattern-card'); if(!card) return; const p=card.getAttribute('data-pattern'); const list=(currentGender==='男'?topData[p].boys:topData[p].girls); const shown=getBatch(p); if(shown<list.length){ ensureMore(p); const oldTop=window.scrollY; render(false); window.scrollTo({top:oldTop,behavior:'auto'}); } }); },{root:null,rootMargin:'0px 0px 320px 0px',threshold:0.01}); document.querySelectorAll('.pattern-card').forEach(card=>{ const lines=card.querySelectorAll('.name-line'); const target=lines[Math.max(0,lines.length-2)]||card; io.observe(target); }); window._namesAutoLoadObserver=io; container.querySelectorAll('[data-more]').forEach(btn=>btn.onclick=()=>{ const p=btn.getAttribute('data-more'); if(!p) return; ensureMore(p); const oldTop=window.scrollY; render(false); window.scrollTo({top:oldTop,behavior:'auto'}); }); container.querySelectorAll('[data-detail-toggle]').forEach(btn=>btn.onclick=()=>{ const item=btn.closest('.name-line'); const detail=item&&item.querySelector('[data-detail-body]'); if(!detail) return; const open=detail.style.display!=='none'; detail.style.display=open?'none':'block'; btn.textContent=open?'展开详情':'收起详情'; }); } function updateTopbar(){ if(!suppressScrollMemoryWrite){ genderScrollMemory[currentGender]=window.scrollY||window.pageYOffset||0; } if(window._namesAutoLoadObserver && !isMobile()){ try{window._namesAutoLoadObserver.disconnect()}catch(e){} } const compact=window.scrollY>32; topbar.classList.toggle('compact',compact); } function getPatternFromHash(){ const raw=decodeURIComponent((location.hash||'').replace(/^#/,'')); return patterns.find(p=>p===raw)||''; } function jumpToPattern(pattern,behavior='smooth'){ if(!pattern) return; activePattern=pattern; const node=container.querySelector(`[data-pattern="${pattern}"]`); if(!node) return; container.querySelectorAll('.pattern-card.active-target').forEach(el=>el.classList.remove('active-target')); node.classList.add('active-target'); node.scrollIntoView({block:'start',behavior}); } function syncHashTarget(behavior='auto'){ const pattern=getPatternFromHash(); if(!pattern) return; activePattern=pattern; requestAnimationFrame(()=>jumpToPattern(pattern,behavior)); } function switchGender(nextGender){ if(nextGender===currentGender) return; const prevGender=currentGender; genderScrollMemory[prevGender]=window.scrollY||window.pageYOffset||0; currentGender=nextGender; body.className=nextGender==='男'?'names-page theme-male':'names-page theme-female'; maleBtn.classList.toggle('active', nextGender==='男'); femaleBtn.classList.toggle('active', nextGender==='女'); suppressScrollMemoryWrite=true; render(false); requestAnimationFrame(()=>{ const target=getPatternFromHash(); if(target){ jumpToPattern(target,'auto'); } else { const targetY=genderScrollMemory[nextGender]==null?0:genderScrollMemory[nextGender]; window.scrollTo({top:targetY,behavior:'auto'}); } requestAnimationFrame(()=>{ suppressScrollMemoryWrite=false; updateTopbar(); }); }); } function render(resetScroll=false){ container.innerHTML = patterns.map(p=>cardHtml(p)).join(''); bindAutoLoad(); updateTopbar(); if(resetScroll){ suppressScrollMemoryWrite=true; window.scrollTo({top:0,behavior:'auto'}); requestAnimationFrame(()=>{ suppressScrollMemoryWrite=false; updateTopbar(); }); } syncHashTarget('auto'); } maleBtn.onclick=()=>switchGender('男'); femaleBtn.onclick=()=>switchGender('女'); window.addEventListener('scroll', updateTopbar,{passive:true}); window.addEventListener('hashchange', ()=>syncHashTarget('smooth')); window.addEventListener('resize', ()=>{ genderScrollMemory[currentGender]=window.scrollY||window.pageYOffset||0; suppressScrollMemoryWrite=true; render(false); requestAnimationFrame(()=>window.scrollTo({top:genderScrollMemory[currentGender]||0,behavior:'auto'})); requestAnimationFrame(()=>{ suppressScrollMemoryWrite=false; updateTopbar(); syncHashTarget('auto'); }); }); render();'''
text = text[:start] + new_tail + text[end:]
path.write_text(text,encoding='utf-8')
print('fixed tail')
